public class ShareReceiverActivity extends AppCompatActivity {

    private TextView titleView;
    private TextView textView;
    private LinearLayout imagesContainer;

    private final ActivityResultLauncher<String[]> openDocumentLauncher =
            registerForActivityResult(new ActivityResultContracts.OpenDocument(), uri -> {
                if (uri != null) {
                    getContentResolver().takePersistableUriPermission(
                            uri,
                            Intent.FLAG_GRANT_READ_URI_PERMISSION
                    );
                    showImages(List.of(uri));
                }
            });

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        ScrollView scrollView = new ScrollView(this);
        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        int pad = (int) (16 * getResources().getDisplayMetrics().density);
        root.setPadding(pad, pad, pad, pad);

        titleView = new TextView(this);
        titleView.setTextSize(18f);
        root.addView(titleView, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));

        textView = new TextView(this);
        textView.setTextSize(15f);
        textView.setPadding(0, pad, 0, pad);
        root.addView(textView, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));

        imagesContainer = new LinearLayout(this);
        imagesContainer.setOrientation(LinearLayout.VERTICAL);
        root.addView(imagesContainer, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));

        scrollView.addView(root);
        setContentView(scrollView);

        handleShareIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleShareIntent(intent);
    }

    private void handleShareIntent(Intent intent) {
        imagesContainer.removeAllViews();
        titleView.setText("");
        textView.setText("");

        if (intent == null) return;

        String action = intent.getAction();
        String type = intent.getType();

        if (!Intent.ACTION_SEND.equals(action) && !Intent.ACTION_SEND_MULTIPLE.equals(action)) {
            titleView.setText("No share content received");
            return;
        }

        CharSequence subject = intent.getCharSequenceExtra(Intent.EXTRA_SUBJECT);
        if (!TextUtils.isEmpty(subject)) {
            titleView.setText(subject);
        } else {
            titleView.setText("Shared Content");
        }

        String sharedText = extractSharedText(intent);
        if (!TextUtils.isEmpty(sharedText)) {
            textView.setText(sharedText);
        } else {
            textView.setText("");
        }

        List<Uri> uris = extractSharedUris(intent);
        if (!uris.isEmpty()) {
            showImages(uris);
        } else if (TextUtils.isEmpty(sharedText)) {
            titleView.setText("No share content received");
        }
    }

    private String extractSharedText(Intent intent) {
        CharSequence cs = intent.getCharSequenceExtra(Intent.EXTRA_TEXT);
        if (!TextUtils.isEmpty(cs)) return cs.toString();

        CharSequence html = intent.getCharSequenceExtra(Intent.EXTRA_HTML_TEXT);
        if (!TextUtils.isEmpty(html)) return html.toString();

        Uri data = intent.getData();
        if (data != null && "text".equalsIgnoreCase(intent.getType())) {
            return data.toString();
        }

        return null;
    }

    private List<Uri> extractSharedUris(Intent intent) {
        List<Uri> result = new ArrayList<>();

        String action = intent.getAction();

        if (Intent.ACTION_SEND.equals(action)) {
            Uri uri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
            if (uri != null) result.add(uri);

            if (result.isEmpty() && intent.getClipData() != null) {
                addClipDataUris(intent.getClipData(), result);
            }
        } else if (Intent.ACTION_SEND_MULTIPLE.equals(action)) {
            ArrayList<Uri> uris = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM);
            if (uris != null) result.addAll(uris);

            if (result.isEmpty() && intent.getClipData() != null) {
                addClipDataUris(intent.getClipData(), result);
            }
        }

        return result;
    }

    private void addClipDataUris(ClipData clipData, List<Uri> out) {
        if (clipData == null) return;
        for (int i = 0; i < clipData.getItemCount(); i++) {
            ClipData.Item item = clipData.getItemAt(i);
            Uri uri = item.getUri();
            if (uri != null) out.add(uri);
        }
    }

    private void showImages(List<Uri> uris) {
        for (Uri uri : uris) {
            ImageView imageView = new ImageView(this);
            imageView.setAdjustViewBounds(true);
            imageView.setScaleType(ImageView.ScaleType.FIT_CENTER);
            int pad = (int) (8 * getResources().getDisplayMetrics().density);
            imageView.setPadding(0, pad, 0, pad);

            imagesContainer.addView(imageView, new LinearLayout.LayoutParams(
                    LinearLayout.LayoutParams.MATCH_PARENT,
                    LinearLayout.LayoutParams.WRAP_CONTENT
            ));

            Bitmap bitmap = decodeBitmapSafely(uri, 1920, 1920);
            if (bitmap != null) {
                imageView.setImageBitmap(bitmap);
            } else {
                imageView.setContentDescription("Unable to load image: " + uri);
            }
        }
    }

    @Nullable
    private Bitmap decodeBitmapSafely(Uri uri, int reqWidth, int reqHeight) {
        try {
            BitmapFactory.Options bounds = new BitmapFactory.Options();
            bounds.inJustDecodeBounds = true;
            try (InputStream in = getContentResolver().openInputStream(uri)) {
                if (in == null) return null;
                BitmapFactory.decodeStream(in, null, bounds);
            }

            if (bounds.outWidth <= 0 || bounds.outHeight <= 0) return null;

            BitmapFactory.Options opts = new BitmapFactory.Options();
            opts.inSampleSize = calculateInSampleSize(bounds, reqWidth, reqHeight);
            opts.inPreferredConfig = Bitmap.Config.ARGB_8888;

            try (InputStream in2 = getContentResolver().openInputStream(uri)) {
                if (in2 == null) return null;
                return BitmapFactory.decodeStream(in2, null, opts);
            }
        } catch (IOException | SecurityException e) {
            return null;
        }
    }

    private int calculateInSampleSize(BitmapFactory.Options options, int reqWidth, int reqHeight) {
        int height = options.outHeight;
        int width = options.outWidth;
        int inSampleSize = 1;

        if (height > reqHeight || width > reqWidth) {
            int halfHeight = height / 2;
            int halfWidth = width / 2;

            while ((halfHeight / inSampleSize) >= reqHeight
                    && (halfWidth / inSampleSize) >= reqWidth) {
                inSampleSize *= 2;
            }
        }

        return Math.max(1, inSampleSize);
    }
}

